Use a sliding window with a hash map/set.

```js
function lengthOfLongestSubstring(s) {
  let left = 0;
  let maxLen = 0;
  const seen = new Map();

  for (let right = 0; right < s.length; right++) {
    const ch = s[right];

    if (seen.has(ch) && seen.get(ch) >= left) {
      left = seen.get(ch) + 1;
    }

    seen.set(ch, right);
    maxLen = Math.max(maxLen, right - left + 1);
  }

  return maxLen;
}
```

