    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)

    state = [0] * n  # 0 = unvisited, 1 = visiting, 2 = visited

    def dfs(node):
        if state[node] == 1:
            return True
        if state[node] == 2:
            return False

        state[node] = 1
        for nei in graph[node]:
            if dfs(nei):
                return True
        state[node] = 2
        return False

    for node in range(n):
        if state[node] == 0 and dfs(node):
            return True
    return False
```

Example:
```python
n = 4
edges = [(0, 1), (1, 2), (2, 3), (3, 1)]
print(has_cycle(n, edges))  # True
```

