const assert = require('assert');

function isPlainObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function cloneValue(value) {
  if (Array.isArray(value)) {
    return value.map(cloneValue);
  }

  if (isPlainObject(value)) {
    const copy = {};
    for (const key of Object.keys(value)) {
      copy[key] = cloneValue(value[key]);
    }
    return copy;
  }

  return value;
}

function deepMerge(a, b) {
  if (!isPlainObject(a) || !isPlainObject(b)) {
    return cloneValue(b);
  }

  const result = cloneValue(a);

  for (const key of Object.keys(b)) {
    const aValue = a[key];
    const bValue = b[key];

    if (isPlainObject(aValue) && isPlainObject(bValue)) {
      result[key] = deepMerge(aValue, bValue);
    } else {
      result[key] = cloneValue(bValue);
    }
  }

  return result;
}

(function runTests() {
  // 1. shallow merge
  assert.deepStrictEqual(
    deepMerge({ a: 1 }, { b: 2 }),
    { a: 1, b: 2 }
  );

  // 2. nested objects merge recursively
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: { y: 2 } }),
    { a: { x: 1, y: 2 } }
  );

  // 3. nested overwrite preserves unrelated keys
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1, z: 3 } }, { a: { x: 9 } }),
    { a: { x: 9, z: 3 } }
  );

  // 4. arrays are overwritten, not merged element-by-element
  assert.deepStrictEqual(
    deepMerge({ items: [1, 2, 3] }, { items: [4, 5] }),
    { items: [4, 5] }
  );

  // 5. array in b overwrites object in a
  assert.deepStrictEqual(
    deepMerge({ value: { nested: true } }, { value: [1, 2] }),
    { value: [1, 2] }
  );

  // 6. null overwrites object
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: null }),
    { a: null }
  );

  // 7. missing keys in b keep values from a
  assert.deepStrictEqual(
    deepMerge({ a: 1, b: 2 }, { b: 3 }),
    { a: 1, b: 3 }
  );

  // 8. conflicting primitive types overwrite with b
  assert.deepStrictEqual(
    deepMerge({ a: 1 }, { a: 'one' }),
    { a: 'one' }
  );

  // 9. empty objects
  assert.deepStrictEqual(
    deepMerge({}, {}),
    {}
  );

  // 10. deep nesting
  assert.deepStrictEqual(
    deepMerge(
      { a: { b: { c: { d: 1 } } } },
      { a: { b: { c: { e: 2 } } } }
    ),
    { a: { b: { c: { d: 1, e: 2 } } } }
