```js
function debounce(fn, delay) {
  if (typeof fn !== 'function') {
    throw new TypeError('Expected fn to be a function');
  }

  let timerId;

  return function debounced(...args) {
    const context = this;
    clearTimeout(timerId);
    timerId = setTimeout(() => {
      fn.apply(context, args);
    }, Math.max(0, delay));
  };
}

module.exports = { debounce };
```

