```js
function normalizePhoneNumber(input, defaultCountry = 'US') {
  if (input == null) {
    return null;
  }

  const raw = String(input).trim();
  if (!raw) {
    return null;
  }

  const country = String(defaultCountry || 'US').toUpperCase();
  const extMatch = raw.match(/(?:ext\.?|extension|x)\s*(\d+)$/i);
  const extension = extMatch ? extMatch[1] : null;
  const withoutExt = extMatch ? raw.slice(0, extMatch.index).trim() : raw;

  if (/[A-WYZa-wyz]/.test(withoutExt)) {
    throw new Error('Phone number contains invalid characters');
  }

  let normalized = withoutExt.replace(/[\s().-]/g, '');

  if (normalized.startsWith('00')) {
    normalized = `+${normalized.slice(2)}`;
  }

  if (normalized.startsWith('+')) {
    if (!/^\+\d+$/.test(normalized)) {
      throw new Error('Phone number contains invalid characters');
    }
  } else {
    if (!/^\d+$/.test(normalized)) {
      throw new Error('Phone number contains invalid characters');
    }

    if (country === 'US') {
      if (normalized.length === 10) {
        normalized = `+1${normalized}`;
      } else if (normalized.length === 11 && normalized.startsWith('1')) {
        normalized = `+${normalized}`;
      } else {
        throw new Error('Invalid US phone number length');
      }
    } else {
      normalized = `+${normalized}`;
    }
  }

  return extension ? `${normalized} x${extension}` : normalized;
}

module.exports = { normalizePhoneNumber };
```

