function unflattenObject(obj) {
  const result = {};

  for (const [flatKey, value] of Object.entries(obj)) {
    if (flatKey === '') {
      throw new Error('Invalid key: empty key');
    }

    const segments = flatKey.split('.');
    if (segments.some(segment => segment === '')) {
      throw new Error(`Invalid key: empty path segment in "${flatKey}"`);
    }

    let current = result;

    for (let i = 0; i < segments.length; i++) {
      const segment = segments[i];
      const isLeaf = i === segments.length - 1;

      if (isLeaf) {
        if (
          Object.prototype.hasOwnProperty.call(current, segment) &&
          current[segment] !== undefined &&
          typeof current[segment] === 'object' &&
          current[segment] !== null
        ) {
          throw new Error(`Conflict at key "${flatKey}": cannot overwrite existing object`);
        }

        current[segment] = value;
        continue;
      }

      if (Object.prototype.hasOwnProperty.call(current, segment)) {
        if (
          current[segment] === null ||
          typeof current[segment] !== 'object' ||
          Array.isArray(current[segment])
        ) {
          throw new Error(`Conflict at key "${flatKey}": "${segment}" is not an object`);
        }
      } else {
        current[segment] = {};
      }

      current = current[segment];
    }
  }

  return result;
}

module.exports = { unflattenObject };
```

