```js
function parseCsvLine(line) {
  if (typeof line !== 'string') {
    throw new TypeError('parseCsvLine expects a string');
  }

  if (line.length === 0) {
    return [''];
  }

  const fields = [];
  let field = '';
  let inQuotes = false;
  let justClosedQuote = false;

  for (let i = 0; i < line.length; i += 1) {
    const char = line[i];

    if (inQuotes) {
      if (char === '"') {
        if (line[i + 1] === '"') {
          field += '"';
          i += 1;
        } else {
          inQuotes = false;
          justClosedQuote = true;
        }
      } else {
        field += char;
      }
      continue;
    }

    if (char === ',') {
      fields.push(field);
      field = '';
      justClosedQuote = false;
      continue;
    }

    if (char === '"') {
      if (field.length !== 0 || justClosedQuote) {
        throw new Error(`Malformed CSV line: unexpected quote at index ${i}`);
      }
      inQuotes = true;
      continue;
    }

    if (justClosedQuote) {
      throw new Error(`Malformed CSV line: unexpected character '${char}' after closing quote at index ${i}`);
    }

    field += char;
  }

  if (inQuotes) {
    throw new Error('Malformed CSV line: unmatched quote');
  }

  fields.push(field);
  return fields;
}

module.exports = { parseCsvLine };
```

