function binarySearchRange(nums, target) {
  function findBoundary(findFirst) {
    let left = 0;
    let right = nums.length - 1;
    let boundary = -1;

    while (left <= right) {
      const mid = left + Math.floor((right - left) / 2);

      if (nums[mid] === target) {
        boundary = mid;
        if (findFirst) {
          right = mid - 1;
        } else {
          left = mid + 1;
        }
      } else if (nums[mid] < target) {
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    }

    return boundary;
  }

  return [findBoundary(true), findBoundary(false)];
}

