function memoize(fn) {
  if (typeof fn !== 'function') {
    throw new TypeError('memoize expects a function');
  }

  const root = new Map();
  const RESULT = Symbol('result');
  const ERROR = Symbol('error');

  return function memoized(...args) {
    let node = root;

    for (const arg of args) {
      const isObjectLike = (typeof arg === 'object' && arg !== null) || typeof arg === 'function';
      const key = isObjectLike ? arg : `primitive:${typeof arg}:${String(arg)}`;

      if (!node.has(key)) {
        node.set(key, new Map());
      }
      node = node.get(key);
    }

    if (node.has(RESULT)) {
      return node.get(RESULT);
    }

    if (node.has(ERROR)) {
      throw node.get(ERROR);
    }

    try {
      const value = fn.apply(this, args);
      node.set(RESULT, value);
      return value;
    } catch (error) {
      node.set(ERROR, error);
      throw error;
    }
  };
}
