```js
function diffArrays(a, b) {
  if (!Array.isArray(a) || !Array.isArray(b)) {
    throw new TypeError('diffArrays expects two arrays');
  }

  const countMap = (arr) => {
    const map = new Map();
    for (const item of arr) {
      map.set(item, (map.get(item) || 0) + 1);
    }
    return map;
  };

  const aCounts = countMap(a);
  const bCounts = countMap(b);
  const keys = new Set([...aCounts.keys(), ...bCounts.keys()]);

  const added = [];
  const removed = [];
  const unchanged = [];

  for (const key of keys) {
    const aCount = aCounts.get(key) || 0;
    const bCount = bCounts.get(key) || 0;
    const shared = Math.min(aCount, bCount);

    for (let i = 0; i < shared; i++) unchanged.push(key);
    for (let i = 0; i < bCount - shared; i++) added.push(key);
    for (let i = 0; i < aCount - shared; i++) removed.push(key);
  }

  return { added, removed, unchanged };
}

module.exports = { diffArrays };
```

Multiplicity matters: duplicates are counted. If a value appears twice in `a` and three times in `b`, one copy is `added`, two are `unchanged`, and none are `removed`.

