```js
function formatDuration(seconds) {
  if (typeof seconds !== 'number' || Number.isNaN(seconds) || !Number.isFinite(seconds)) {
    throw new TypeError('seconds must be a finite number');
  }

  if (seconds < 0) {
    throw new RangeError('seconds must be non-negative');
  }

  if (seconds === 0) {
    return '0s';
  }

  const totalMilliseconds = Math.round(seconds * 1000);
  const wholeSeconds = Math.floor(totalMilliseconds / 1000);
  const remainingMilliseconds = totalMilliseconds % 1000;

  const hours = Math.floor(wholeSeconds / 3600);
  const minutes = Math.floor((wholeSeconds % 3600) / 60);
  const secs = wholeSeconds % 60;

  const parts = [];

  if (hours > 0) parts.push(`${hours}h`);
  if (minutes > 0) parts.push(`${minutes}m`);
  if (secs > 0) parts.push(`${secs}s`);
  if (remainingMilliseconds > 0) parts.push(`${remainingMilliseconds}ms`);

  return parts.join(' ');
}

module.exports = { formatDuration };
```

