function slugify(input) {
  if (input == null) return '';

  const transliterationMap = {
    ß: 'ss',
    Æ: 'ae',
    æ: 'ae',
    Ø: 'o',
    ø: 'o',
    Å: 'a',
    å: 'a',
    Þ: 'th',
    þ: 'th',
    Ð: 'd',
    ð: 'd',
    Ł: 'l',
    ł: 'l',
    Œ: 'oe',
    œ: 'oe',
  };

  const cyrillicMap = {
    А: 'a', Б: 'b', В: 'v', Г: 'g', Д: 'd', Е: 'e', Ё: 'e', Ж: 'zh', З: 'z', И: 'i',
    Й: 'i', К: 'k', Л: 'l', М: 'm', Н: 'n', О: 'o', П: 'p', Р: 'r', С: 's', Т: 't',
    У: 'u', Ф: 'f', Х: 'h', Ц: 'ts', Ч: 'ch', Ш: 'sh', Щ: 'shch', Ъ: '', Ы: 'y', Ь: '',
    Э: 'e', Ю: 'yu', Я: 'ya',
    а: 'a', б: 'b', в: 'v', г: 'g', д: 'd', е: 'e', ё: 'e', ж: 'zh', з: 'z', и: 'i',
    й: 'i', к: 'k', л: 'l', м: 'm', н: 'n', о: 'o', п: 'p', р: 'r', с: 's', т: 't',
    у: 'u', ф: 'f', х: 'h', ц: 'ts', ч: 'ch', ш: 'sh', щ: 'shch', ъ: '', ы: 'y', ь: '',
    э: 'e', ю: 'yu', я: 'ya',
  };

  const charMap = { ...transliterationMap, ...cyrillicMap };

  const replaced = String(input)
    .trim()
    .replace(/[\u2012\u2013\u2014\u2015]/g, '-')
    .replace(/[&]/g, ' and ')
    .replace(/[']/g, '')
    .replace(/./gu, (ch) => (charMap[ch] !== undefined ? charMap[ch] : ch));

  const normalized = replaced
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, ' ')
    .replace(/[\s_-]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-+|-+$/g, '');

  return normalized;
}

module.exports = { slugify };
