function humanFileSize(bytes) {
  if (typeof bytes !== 'number' || !Number.isFinite(bytes)) {
    throw new TypeError('bytes must be a finite number');
  }

  const base = 1024;
  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB'];
  const sign = bytes < 0 ? '-' : '';
  const value = Math.abs(bytes);

  if (value === 0) return '0 B';

  let unitIndex = Math.min(
    Math.floor(Math.log(value) / Math.log(base)),
    units.length - 1
  );

  let scaled = value / Math.pow(base, unitIndex);

  if (scaled >= base && unitIndex < units.length - 1) {
    unitIndex += 1;
    scaled /= base;
  }

  const formatted =
    unitIndex === 0 || Number.isInteger(scaled)
      ? String(scaled)
      : scaled.toFixed(1).replace(/\.0$/, '');

  return `${sign}${formatted} ${units[unitIndex]}`;
}

module.exports = { humanFileSize };
```

