function mergeIntervals(intervals) {
  if (!Array.isArray(intervals)) {
    throw new TypeError('intervals must be an array');
  }

  if (intervals.length === 0) {
    return [];
  }

  const normalized = intervals.map((interval, index) => {
    if (!Array.isArray(interval) || interval.length !== 2) {
      throw new TypeError(`interval at index ${index} must be a 2-item array`);
    }

    const [start, end] = interval;

    if (!Number.isFinite(start) || !Number.isFinite(end)) {
      throw new TypeError(`interval at index ${index} must contain finite numbers`);
    }

    if (start > end) {
      throw new RangeError(`interval at index ${index} has start greater than end`);
    }

    return [start, end];
  });

  normalized.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

  const merged = [normalized[0]];

  for (let i = 1; i < normalized.length; i++) {
    const [start, end] = normalized[i];
    const last = merged[merged.length - 1];

    if (start <= last[1]) {
      last[1] = Math.max(last[1], end);
    } else {
      merged.push([start, end]);
    }
  }

  return merged;
}

module.exports = { mergeIntervals };
```

