```js
function wordWrap(text, maxWidth) {
  if (!Number.isInteger(maxWidth) || maxWidth < 1) {
    throw new TypeError('maxWidth must be a positive integer');
  }
  if (text === '') {
    return '';
  }

  const paragraphs = String(text).split('\n');
  const wrapped = paragraphs.map(wrapParagraph);
  return wrapped.join('\n');

  function wrapParagraph(paragraph) {
    if (paragraph === '') {
      return '';
    }

    const tokens = paragraph.match(/\S+|\s+/g) || [];
    const lines = [];
    let line = '';

    for (const token of tokens) {
      if (/^\s+$/.test(token)) {
        if (line !== '') {
          line += token;
        }
        continue;
      }

      if (line === '') {
        if (token.length <= maxWidth) {
          line = token;
        } else {
          lines.push(...splitLongWord(token, maxWidth));
        }
        continue;
      }

      if (line.length + token.length <= maxWidth) {
        line += token;
        continue;
      }

      lines.push(trimTrailingSpaces(line));

      if (token.length <= maxWidth) {
        line = token;
      } else {
        const parts = splitLongWord(token, maxWidth);
        lines.push(...parts.slice(0, -1));
        line = parts[parts.length - 1];
      }
    }

    if (line !== '') {
      lines.push(trimTrailingSpaces(line));
    }

    return lines.join('\n');
  }

  function splitLongWord(word, width) {
    const parts = [];
    for (let i = 0; i < word.length; i += width) {
      parts.push(word.slice(i, i + width));
    }
    return parts;
  }

  function trimTrailingSpaces(value) {
    return value.replace(/[ \t]+$/g, '');
  }
}

module.exports = { wordWrap };
```

