```js
function buildTree(items) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  const nodes = new Map();
  const inputOrder = [];

  for (let i = 0; i < items.length; i += 1) {
    const item = items[i];

    if (item === null || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${i}] must be an object`);
    }

    if (!Object.prototype.hasOwnProperty.call(item, 'id')) {
      throw new Error(`items[${i}] is missing id`);
    }

    const { id, parentId = null } = item;

    if (id === null || id === undefined) {
      throw new Error(`items[${i}] has invalid id`);
    }

    if (nodes.has(id)) {
      throw new Error(`Duplicate id: ${String(id)}`);
    }

    nodes.set(id, {
      ...item,
      parentId,
      children: [],
    });
    inputOrder.push(id);
  }

  const roots = [];

  for (const id of inputOrder) {
    const node = nodes.get(id);

    if (node.parentId === null || node.parentId === undefined) {
      roots.push(node);
      continue;
    }

    if (node.parentId === node.id) {
      throw new Error(`Cycle detected: node ${String(node.id)} references itself`);
    }

    const parent = nodes.get(node.parentId);
    if (!parent) {
      throw new Error(
        `Missing parent: ${String(node.parentId)} for node ${String(node.id)}`
      );
    }

    parent.children.push(node);
  }

  const visiting = new Set();
  const visited = new Set();

  function dfs(node) {
    if (visited.has(node.id)) {
      return;
    }

    if (visiting.has(node.id)) {
      throw new Error(`Cycle detected involving node ${String(node.id)}`);
    }

    visiting.add(node.id);
    for (const child of node.children) {
      dfs(child);
    }
    visiting.delete(node.id);
    visited.add(node.id);
  }

  for (const id of inputOrder) {
    dfs(nodes.get(id));
  }

  return roots;
}

module.exports = { buildTree };
```

