```js
/**
 * Sort objects by multiple keys and directions without mutating the input.
 *
 * Assumptions:
 * - `rules` is an array of `{ key, direction }` objects.
 * - `direction` may be `'asc'` or `'desc'` (case-insensitive). Invalid or missing
 *   directions default to ascending.
 * - Missing properties (`undefined`) sort after defined values in ascending order
 *   and before defined values in descending order.
 * - `null` is treated as a normal value, distinct from `undefined`.
 * - When values have different types, they are ordered by a deterministic type
 *   precedence before comparing within the same type:
 *   number < bigint < string < boolean < object < symbol < function.
 * - Comparisons within the same type use natural JS ordering where practical.
 * - The sort is stable: if all rules compare equal, original order is preserved.
 */
function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }

  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const normalizedRules = rules
    .filter(rule => rule && typeof rule.key === 'string' && rule.key.length > 0)
    .map(rule => ({
      key: rule.key,
      direction: String(rule.direction || 'asc').toLowerCase() === 'desc' ? 'desc' : 'asc',
    }));

  if (normalizedRules.length === 0) {
    return items.slice();
  }

  return items
    .map((item, index) => ({ item, index }))
    .sort((a, b) => {
      for (const rule of normalizedRules) {
        const result = compareValues(a.item?.[rule.key], b.item?.[rule.key], rule.direction);
        if (result !== 0) return result;
      }
      return a.index - b.index;
    })
    .map(entry => entry.item);
}

function compareValues(a, b, direction) {
  const multiplier = direction === 'desc' ? -1 : 1;

  const aMissing = a === undefined;
  const bMissing = b === undefined;

  if (aMissing || bMissing) {
    if (aMissing && bMissing) return 0;
    return aMissing ? 1 * multiplier : -1 * multiplier;
  }

  const typeOrder = {
    number: 0,
    bigint: 1,
    string: 2,
    boolean: 3,
    object: 4,
    symbol: 5,
    function: 6,
  };

  const typeA = a === null ? 'object' : typeof a;
  const typeB = b === null ? 'object' : typeof b;

  if (typeA !== typeB) {
    return (typeOrder[typeA] - typeOrder[typeB]) * multiplier;
  }

  let base;

  switch (typeA) {
    case 'number':
      if (Number.isNaN(a) && Number.isNaN(b)) base = 0;
      else if (Number.isNaN(a)) base = 1;
      else if (Number.isNaN(b)) base = -1;
      else base = a < b ? -1 : a > b ? 1 : 0;
      break;
    case 'bigint':
      base = a < b ? -1 : a > b ? 1 : 0;
      break;
    case 'string':
      base = a.localeCompare(b);
      break;
    case 'boolean':
      base = a === b ? 0 : a ? 1 : -1;
      break;
    case 'object':
      if (a === b) base = 0;
      else if (a === null) base = -1;
      else if (b === null) base = 1;
      else {
        const aTag = Object.prototype.toString.call(a);
        const bTag = Object.prototype.toString.call(b);
        base = aTag.localeCompare(bTag);
      }
      break;
    case 'symbol':
    case 'function':
      base = String(a).localeCompare(String(b));
      break;
    default:
      base = 0;
  }

  return base * multiplier;
}

module.exports = { sortByMultiple };
```

