function parseBoolean(input) {
  if (typeof input === 'boolean') return input;

  if (typeof input === 'number') {
    if (input === 1) return true;
    if (input === 0) return false;
    throw new TypeError('Invalid boolean number');
  }

  if (typeof input === 'string') {
    const value = input.trim().toLowerCase();

    if (value === 'true' || value === '1' || value === 'yes') return true;
    if (value === 'false' || value === '0' || value === 'no') return false;
    if (value === '') throw new TypeError('Empty string is not a valid boolean value');

    throw new TypeError(`Invalid boolean string: ${input}`);
  }

  if (input == null) {
    throw new TypeError('Null or undefined is not a valid boolean value');
  }

  throw new TypeError(`Unsupported type: ${typeof input}`);
}

module.exports = { parseBoolean };
```

