function transposeCsv(rows) {
  if (!Array.isArray(rows) || rows.length === 0) return [];

  const normalizedRows = rows.map((row) => {
    if (!Array.isArray(row)) return [];
    return row.map((cell) => {
      if (cell == null) return '';
      return String(cell);
    });
  });

  const maxColumns = normalizedRows.reduce((max, row) => Math.max(max, row.length), 0);
  if (maxColumns === 0) return [];

  return Array.from({ length: maxColumns }, (_, colIndex) =>
    normalizedRows.map((row) => (colIndex < row.length ? row[colIndex] : ''))
  );
}

module.exports = { transposeCsv };
```

