function minWindowSubstring(text, pattern) {
  if (pattern.length === 0 || text.length === 0 || pattern.length > text.length) {
    return pattern.length === 0 ? "" : "";
  }

  const need = new Map();
  for (const ch of pattern) {
    need.set(ch, (need.get(ch) || 0) + 1);
  }

  const windowCounts = new Map();
  let required = need.size;
  let formed = 0;
  let left = 0;
  let bestStart = 0;
  let bestLen = Infinity;

  for (let right = 0; right < text.length; right++) {
    const ch = text[right];
    windowCounts.set(ch, (windowCounts.get(ch) || 0) + 1);

    if (need.has(ch) && windowCounts.get(ch) === need.get(ch)) {
      formed++;
    }

    while (formed === required) {
      const windowLen = right - left + 1;
      if (windowLen < bestLen) {
        bestLen = windowLen;
        bestStart = left;
      }

      const leftChar = text[left];
      windowCounts.set(leftChar, windowCounts.get(leftChar) - 1);
      if (need.has(leftChar) && windowCounts.get(leftChar) < need.get(leftChar)) {
        formed--;
      }
      left++;
    }
  }

  return bestLen === Infinity ? "" : text.slice(bestStart, bestStart + bestLen);
}

module.exports = { minWindowSubstring };
