function serializeForm(fields) {
  if (!Array.isArray(fields) || fields.length === 0) return '';

  const parts = [];

  for (const field of fields) {
    if (!field || typeof field.name !== 'string' || field.name.length === 0) continue;

    const name = encodeURIComponent(field.name);
    const rawValue = field.value == null ? '' : String(field.value);
    const value = encodeURIComponent(rawValue);

    parts.push(`${name}=${value}`);
  }

  return parts.join('&');
}

module.exports = { serializeForm };
