function descriptiveStats(numbers) {
  if (!Array.isArray(numbers)) {
    throw new TypeError('numbers must be an array');
  }

  if (numbers.length === 0) {
    return {
      count: 0,
      min: null,
      max: null,
      mean: null,
      median: null,
      mode: null,
      range: null,
    };
  }

  for (const value of numbers) {
    if (typeof value !== 'number' || !Number.isFinite(value)) {
      throw new TypeError('all values must be finite numbers');
    }
  }

  const sorted = [...numbers].sort((a, b) => a - b);
  const count = sorted.length;
  const min = sorted[0];
  const max = sorted[count - 1];
  const sum = sorted.reduce((acc, n) => acc + n, 0);
  const mean = sum / count;

  const middle = Math.floor(count / 2);
  const median =
    count % 2 === 1
      ? sorted[middle]
      : (sorted[middle - 1] + sorted[middle]) / 2;

  const frequencies = new Map();
  for (const n of sorted) {
    frequencies.set(n, (frequencies.get(n) || 0) + 1);
  }

  let highestFrequency = 0;
  for (const freq of frequencies.values()) {
    if (freq > highestFrequency) highestFrequency = freq;
  }

  const modes = [...frequencies.entries()]
    .filter(([, freq]) => freq === highestFrequency)
    .map(([value]) => value)
    .sort((a, b) => a - b);

  const mode = highestFrequency === 1 ? null : modes.length === 1 ? modes[0] : modes;

  return {
    count,
    min,
    max,
    mean,
    median,
    mode,
    range: max - min,
  };
}

module.exports = { descriptiveStats };
