function nearestPalindrome(n) {
  if (typeof n !== 'string' || !/^[0-9]+$/.test(n) || n.length === 0) {
    throw new TypeError('Input must be a non-empty string of digits');
  }

  if (n.length > 1 && n[0] === '0') {
    throw new TypeError('Input must not contain leading zeros');
  }

  if (n === '0') {
    throw new RangeError('Input must be a positive integer string');
  }

  const isPalindrome = (s) => s === s.split('').reverse().join('');

  const cmpNumStr = (a, b) => {
    if (a.length !== b.length) return a.length - b.length;
    return a < b ? -1 : a > b ? 1 : 0;
  };

  const subOne = (s) => {
    const arr = s.split('');
    let i = arr.length - 1;
    while (i >= 0 && arr[i] === '0') {
      arr[i] = '9';
      i--;
    }
    if (i < 0) return '0';
    arr[i] = String.fromCharCode(arr[i].charCodeAt(0) - 1);
    while (arr.length > 1 && arr[0] === '0') arr.shift();
    return arr.join('');
  };

  const addOne = (s) => {
    const arr = s.split('');
    let i = arr.length - 1;
    let carry = 1;
    while (i >= 0 && carry) {
      const d = arr[i].charCodeAt(0) - 48 + carry;
      arr[i] = String(d % 10);
      carry = d >= 10 ? 1 : 0;
      i--;
    }
    if (carry) arr.unshift('1');
    return arr.join('');
  };

  const absDiff = (a, b) => {
    let x = a;
    let y = b;
    if (cmpNumStr(x, y) < 0) {
      const tmp = x;
      x = y;
      y = tmp;
    }

    const xa = x.split('').map(c => c.charCodeAt(0) - 48);
    const ya = y.padStart(x.length, '0').split('').map(c => c.charCodeAt(0) - 48);

    for (let i = xa.length - 1; i >= 0; i--) {
      if (xa[i] < ya[i]) {
        xa[i] += 10;
        xa[i - 1]--;
      }
      xa[i] -= ya[i];
    }

    while (xa.length > 1 && xa[0] === 0) xa.shift();
    return xa.join('');
  };

  const mirrorFromPrefix = (prefix, totalLen) => {
    const leftLen = Math.ceil(totalLen / 2);
    if (prefix.length !== leftLen) {
      throw new Error('Invalid prefix length');
    }
    const left = prefix;
    const right = prefix
      .slice(0, totalLen % 2 === 0 ? leftLen : leftLen - 1)
      .split('')
      .reverse()
      .join('');
    return left + right;
  };

  const len = n.length;
  const halfLen = Math.ceil(len / 2);
  const prefix = n.slice(0, halfLen);

  const candidates = new Set();
  candidates.add('9'.repeat(len - 1) || '0');
  candidates.add('1' + '0'.repeat(len - 1) + '1');

  [subOne(prefix), prefix, addOne(prefix)].forEach(p => {
    if (p !== '0' && p.length === halfLen) {
      candidates.add(mirrorFromPrefix(p, len));
    } else if (p.length < halfLen) {
      candidates.add('9'.repeat(len - 1));
    } else if (p.length > halfLen) {
      candidates.add(mirrorFromPrefix(p, len + 1));
    }
  });

  candidates.delete(n);

  let best = null;
  let bestDiff = null;

  for (const cand of candidates) {
    if (!cand || cand === '0') continue;
    const diff = absDiff(cand, n);
    if (
      best === null ||
      cmpNumStr(diff, bestDiff) < 0 ||
      (cmpNumStr(diff, bestDiff) === 0 && cmpNumStr(cand, best) < 0)
    ) {
      best = cand;
      bestDiff = diff;
    }
  }

  return best;
}

