(function runTests() {
  const cases = [
    ['1', '2'],                  // single digit
    ['9', '8'],                  // single digit tie -> smaller
    ['10', '9'],                 // power of ten
    ['1000', '999'],             // larger power of ten
    ['11', '9'],                 // already palindromic
    ['121', '111'],              // already palindromic
    ['99', '101'],               // all 9s
    ['123', '121'],              // ordinary case
    ['1283', '1331'],            // ordinary case
    ['1001', '999'],             // palindromic, tie -> smaller
    ['999999999999999999', '1000000000000000001'], // very large input
    ['1000000000000000000', '999999999999999999'], // very large power of ten
  ];

  for (const [input, expected] of cases) {
    const actual = nearestPalindrome(input);
    if (actual !== expected) {
      throw new Error(`nearestPalindrome(${input}) => ${actual}, expected ${expected}`);
    }
  }

  const invalid = ['', '001', '12a', '-1', '0', 123, null, undefined];
  for (const input of invalid) {
    let threw = false;
    try {
      nearestPalindrome(input);
    } catch {
      threw = true;
    }
    if (!threw) {
      throw new Error(`Expected invalid input to throw: ${String(input)}`);
    }
  }

  console.log('All tests passed');
})();
