  // 5. Multiple peaks: returns any valid peak
  {
    const nums = [1, 3, 2, 4, 1];
    const result = findPeakElement(nums);
    assert.ok([1, 3].includes(result));
  }

  // 6. Equal adjacent values: plateau is not a peak
  assert.strictEqual(findPeakElement([1, 2, 2, 1]), -1);

  // 7. Negative numbers
