  // 8. Flat array: no strict peak
  assert.strictEqual(findPeakElement([7, 7, 7]), -1);

  // 9. Peak in the middle
  assert.strictEqual(findPeakElement([1, 5, 1]), 1);

  // 10. Equal values near a valid endpoint peak
