function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const s = input.trim();
  if (s.length === 0) {
    throw new Error('Roman numeral cannot be empty');
  }
  if (!/^[ivxlcdm]+$/i.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  const values = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };

  const nonRepeatable = new Set(['V', 'L', 'D']);
  const validSubtractive = new Set(['IV', 'IX', 'XL', 'XC', 'CD', 'CM']);
  const chars = s.toUpperCase();

  let total = 0;
  let i = 0;
  let repeatCount = 1;

  while (i < chars.length) {
    const current = chars[i];
    const currentValue = values[current];
    const next = chars[i + 1];
    const nextValue = next ? values[next] : 0;

    if (i > 0 && chars[i - 1] === current) {
      repeatCount += 1;
    } else {
      repeatCount = 1;
    }

    if (nonRepeatable.has(current) && repeatCount > 1) {
      throw new Error(`Symbol ${current} cannot repeat`);
    }

    if (!nonRepeatable.has(current) && repeatCount > 3) {
      throw new Error(`Symbol ${current} cannot repeat more than 3 times`);
    }

    if (currentValue < nextValue) {
      const pair = current + next;

      if (!validSubtractive.has(pair)) {
        throw new Error(`Invalid subtractive pair: ${pair}`);
      }

      if (repeatCount > 1) {
        throw new Error(`Invalid repetition before subtractive pair: ${pair}`);
      }

      const afterNext = chars[i + 2];
      const afterNextValue = afterNext ? values[afterNext] : 0;
      if (afterNextValue > currentValue && afterNextValue >= nextValue) {
        throw new Error('Malformed Roman numeral sequence');
      }

      total += nextValue - currentValue;
      i += 2;
      repeatCount = 1;
      continue;
    }

    if (i > 0) {
      const prev = chars[i - 1];
      const prevValue = values[prev];
      if (prevValue < currentValue) {
        throw new Error('Malformed Roman numeral sequence');
      }
    }

    total += currentValue;
    i += 1;
  }

  return total;
}

